package com.careeros.provider.web;import com.careeros.common.web.PageResponse;import com.careeros.provider.application.SyncHistoryService;import com.careeros.provider.domain.*;import org.springframework.data.domain.Pageable;import org.springframework.web.bind.annotation.*;import java.time.Instant;import java.util.*;import java.util.stream.Collectors;
@RestController public class ProviderMonitoringController{private final SyncHistoryService s;public ProviderMonitoringController(SyncHistoryService s){this.s=s;}@GetMapping("/api/sync-history")public PageResponse<Response>all(Pageable p){return PageResponse.from(s.list(p),this::out);}@GetMapping("/api/sync-history/company/{id}")public PageResponse<Response>company(@PathVariable UUID id,Pageable p){return PageResponse.from(s.company(id,p),this::out);}@GetMapping("/api/sync-history/provider/{provider}")public PageResponse<Response>provider(@PathVariable ProviderType provider,Pageable p){return PageResponse.from(s.provider(provider,p),this::out);}@GetMapping("/api/provider-health")public List<Health>health(){return s.all().stream().collect(Collectors.groupingBy(SyncHistory::getProvider)).entrySet().stream().map(e->{var h=e.getValue();long ok=h.stream().filter(SyncHistory::isSuccess).count();return new Health(e.getKey(),h.stream().map(x->x.getCompany().getId()).distinct().count(),h.isEmpty()?0:ok*100.0/h.size(),h.stream().mapToLong(SyncHistory::getDurationMs).average().orElse(0),h.stream().map(SyncHistory::getCompletedAt).max(Instant::compareTo).orElse(null),h.stream().mapToLong(SyncHistory::getJobsFound).sum(),h.size()-ok);}).toList();}private Response out(SyncHistory h){return new Response(h.getId(),h.getCompany().getId(),h.getCompany().getName(),h.getProvider(),h.getStartedAt(),h.getCompletedAt(),h.getDurationMs(),h.isSuccess(),h.getJobsFound(),h.getJobsAdded(),h.getJobsUpdated(),h.getErrorMessage());}public record Response(UUID id,UUID companyId,String company,ProviderType provider,Instant startedAt,Instant completedAt,long durationMs,boolean success,int jobsFound,int jobsAdded,int jobsUpdated,String errorMessage){}public record Health(ProviderType provider,long companiesMonitored,double successRate,double averageSyncTimeMs,Instant lastSync,long jobsDiscovered,long failureCount){}}
